	('a08b3908-5aaa-4804-aa73-3b02d56bcb01', '7d95ca36-9aae-4472-9b51-728da28999e9', '2-Week Basic', 14, 20, 2850.00, 1890.00, 2530000, NULL, NULL, NULL, NULL, NULL, '["Experience 14 days of English language study combined with Melbourne''s world-class arts and cultural scene for families.", "✓ Host family accommodation in Melbourne''s inner suburbs with daily breakfast and dinner", "✓ 20 General English lessons per week with certified, experienced instructors", "✓ Airport pickup from Melbourne Tullamarine Airport on arrival", "✓ Welcome dinner event connecting new students and their families", "✓ Guided visit to the National Gallery of Victoria and Melbourne Arts Precinct", "✓ One weekend cultural excursion — Dandenong Ranges or Great Ocean Road scenic day trip", "✓ Certificate of completion awarded at end of program", "✗ International airfare and airport taxes not covered", "✗ Travel insurance must be arranged independently before departure", "✗ Personal spending money and optional shopping tours not included", "✗ Lunches and snacks on excursion days at own expense"]', 'active', '2026-03-19 13:22:36.727319', '2026-03-27 01:38:10.178381', 1, 2, NULL, NULL, NULL),
	('f2f6b8da-2746-42aa-9042-c852c9b12ccb', 'fddf8d72-2789-454a-ba54-f4046affecf0', 'Package A', 14, NULL, 5800.00, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '["A sample 14-day English program in Sydney used for system testing and package configuration demonstrations.", "✓ Host family accommodation with standard daily meals included", "✓ 20 General English lessons per week with qualified teachers", "✓ Airport pickup from Sydney International Airport on arrival", "✓ Welcome orientation and campus familiarisation tour on day one", "✓ One supervised weekend excursion to a Sydney attraction", "✓ Edubee student portal access for real-time schedule and messaging", "✓ Program completion certificate issued at end of test package", "✗ International airfare not included in test package", "✗ Travel insurance to be arranged by participant", "✗ Personal spending money not covered", "✗ Optional activity upgrades at additional cost"]', 'active', '2026-03-20 16:08:58.637507', '2026-03-27 07:37:00.958', 1, 1, NULL, NULL, NULL),
