	('3d1edf88-af68-402f-a247-238c0f47dc1c', 'ad692b74-66e1-4af6-a1b4-e6ed71b22209', '2-Week Intensive', 14, 20, 3200.00, NULL, 2976000, 480000, 117000.00, NULL, 4350.00, NULL, '["A fast-paced 14-day intensive English program in Bangkok — designed for motivated learners seeking rapid language improvement.", "✓ Student guesthouse accommodation in Bangkok''s Sukhumvit district with Wi-Fi", "✓ 25 intensive English lessons per week — grammar, pronunciation, fluency drills", "✓ Suvarnabhumi Airport pickup included on arrival day", "✓ Weekly one-on-one tutoring session with your assigned language coach", "✓ Bangkok city orientation tour: Grand Palace, Chao Phraya River, weekend market", "✓ English pronunciation lab and speaking confidence workshop included", "✓ Progress assessment with personalised feedback report at program end", "✗ International airfare to Bangkok not included in program fees", "✗ Thailand tourist visa fees and travel insurance at own expense", "✗ Meals outside guesthouse breakfast plan not included", "✗ Optional Koh Samet beach day trip at additional cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:38:41.00972', 1, 2, NULL, NULL, NULL),
	('ab58e341-49bd-45ca-a94b-5fcc6072f498', '7d95ca36-9aae-4472-9b51-728da28999e9', '3-Week Arts Program', 21, 18, 4200.00, NULL, 3906000, 630000, 153000.00, NULL, 5700.00, NULL, '["Explore creativity and language over 21 inspiring days in Melbourne — where arts, design, and English learning beautifully converge.", "✓ Host family accommodation in Melbourne''s artsy inner suburbs with daily meals", "✓ 20 English language lessons per week integrated with arts and design themes", "✓ Melbourne Airport arrival transfer included in program", "✓ Studio workshops: painting, sculpture, printmaking, and digital design", "✓ Guided tour of NGV International and the Australian Centre for Contemporary Art", "✓ Participation in Melbourne Open Studio art walk with local artists", "✓ Personal art portfolio developed over 3 weeks, presented at closing showcase", "✗ International airfare to Melbourne not included in program price", "✗ Travel insurance to be arranged independently before departure", "✗ Art supply upgrades beyond provided materials at own expense", "✗ Optional Healesville Sanctuary wildlife excursion at additional cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:39:00.404092', 1, 2, NULL, NULL, NULL),
	('a0aedf37-77c8-48b5-a7fd-131849cd2bfa', '3084c658-17a1-434d-b3e4-36e0a1f8eb2f', '4-Week Academic', 28, 20, 6200.00, NULL, 5766000, 930000, 226000.00, NULL, 8430.00, NULL, '["Four weeks of deep academic English immersion in charming Dublin — where Irish culture and educational excellence go hand in hand.", "✓ Homestay accommodation with an Irish host family, breakfast and dinner daily", "✓ 30 academic English lessons weekly covering university-level grammar and composition", "✓ Dublin Airport transfer included on confirmed arrival date", "✓ Academic coaching sessions: argumentation, literature analysis, and essay structure", "✓ Literary walking tour of Dublin — James Joyce, Oscar Wilde, and Samuel Beckett sites", "✓ Day trip to the Cliffs of Moher and Galway Bay on the Wild Atlantic Way", "✓ Certificate of academic excellence with detailed performance assessment", "✗ International airfare and Ireland entry visa fees not included", "✗ Travel insurance mandatory — must be arranged by participant before flying", "✗ Pub crawl and nightlife activities outside program scope and not covered", "✗ Optional Giant''s Causeway trip to Northern Ireland at extra cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:39:04.262968', 2, 2, NULL, NULL, NULL),
	('394dc150-f157-4498-b88e-56936d924d34', 'f904fe12-b84a-4bb8-a219-722e021dafbc', '2-Week Basic', 14, 20, 2850.00, 1890.00, 2530000, NULL, NULL, NULL, NULL, NULL, '["A perfect 14-day introduction to English immersion in vibrant Vancouver for families seeking quality winter education abroad.", "✓ Warm and welcoming host family accommodation including breakfast and dinner daily", "✓ 20 structured General English lessons per week led by certified TESOL teachers", "✓ Airport pickup from YVR International Airport on arrival day included", "✓ Welcome orientation session with city map, safety briefing and campus tour", "✓ One fully supervised weekend excursion to Whistler or Capilano Suspension Bridge", "✓ Student activity card providing discounts at local museums, cafés, and attractions", "✓ Weekly written progress report shared with parents or guardians", "✗ International airfare and departure taxes not included", "✗ Travel insurance is not provided — strongly recommended before travel", "✗ Personal spending money, souvenirs and optional meal upgrades not covered", "✗ Optional premium activity upgrades available at additional cost"]', 'active', '2026-03-21 15:51:37.274692', '2026-03-27 01:38:06.268985', 1, 1, 'percentage', 10.00, NULL),
