	('3d317817-1852-48ff-bac9-55d67bb1590c', 'ab0194f8-57f6-4ced-b6a8-cceef1c750ee', '3-Week Academic', 21, 12, NULL, NULL, 5420000, NULL, NULL, NULL, NULL, 3200.00, '["Three weeks in London dedicated to academic English excellence — intensive study, iconic culture, and lifelong friendships.", "✓ Host family accommodation in London suburb with full board on weekdays", "✓ 30 academic English lessons weekly covering IELTS and Cambridge test skills", "✓ Airport transfer from Heathrow or Gatwick on arrival day", "✓ Study skills workshop: essay writing, note-taking, and research methodology", "✓ Day trip to Oxford University city — guided walking tour of college grounds", "✓ West End musical or play included in program schedule", "✓ Certificate of academic completion and teacher assessment report", "✗ International airfare and applicable UK visa fees not covered", "✗ Travel and medical insurance is participant''s responsibility", "✗ Lunch on school days available at campus café at own cost", "✗ Optional Stonehenge or Edinburgh weekend trips at extra cost"]', 'active', '2026-03-21 15:51:37.315072', '2026-03-27 01:38:48.736954', 1, 2, 'fixed', NULL, 300.00),
	('b7f2a192-ce1d-47e7-8f8c-e1530b814c74', 'ab0194f8-57f6-4ced-b6a8-cceef1c750ee', '3-Week Academic', 21, 12, NULL, NULL, 5420000, NULL, NULL, NULL, NULL, 3200.00, '["Develop world-class academic English in London over 21 intensive days — ideal for aspiring university and scholarship applicants.", "✓ Comfortable host family homestay accommodation near program campus", "✓ 30 weekly lessons focused on academic writing, debate, and critical analysis", "✓ Arrival airport transfer from Heathrow or Gatwick included", "✓ Mock IELTS practice test with full scoring and feedback session", "✓ Visit to the Houses of Parliament and Westminster Abbey guided tour", "✓ Cultural immersion weekend: Borough Market, South Bank Walk, Tate Modern", "✓ Personalised end-of-program report for university scholarship applications", "✗ International flight tickets and UK visa application fees not included", "✗ Travel insurance required — must be arranged before arrival", "✗ IELTS official exam registration not included in program fee", "✗ Personal spending and optional excursion upgrades at own cost"]', 'active', '2026-03-18 01:11:40.334563', '2026-03-27 01:38:52.628202', 2, 1, 'fixed', NULL, 300.00),
	('2f9ca97f-f691-4244-862f-cbd6a0dff7c4', 'ab0194f8-57f6-4ced-b6a8-cceef1c750ee', '3-Week Academic', 21, 12, NULL, NULL, 5420000, NULL, NULL, NULL, NULL, 3200.00, '["The ultimate 3-week academic English experience in London — preparing families with two adults for university-level success.", "✓ Host family accommodation with breakfast, dinner, and weekend meals", "✓ 30 academic English lessons weekly with one-on-one teacher consultation slots", "✓ London airport transfer on arrival date from Heathrow or Gatwick", "✓ Cambridge academic writing workshop with peer review and instructor feedback", "✓ Full-day excursion to Cambridge University — punting and college visits", "✓ London bus top tour and Tower Bridge experience included", "✓ Formal farewell ceremony with certificate and portfolio handover", "✗ International airfare not included in program pricing", "✗ UK student visa or family visit visa to be arranged by participants", "✗ Travel insurance not provided — families must arrange coverage before travel", "✗ Optional Windsor Castle or Stratford-upon-Avon day trips at extra cost"]', 'active', '2026-03-19 13:22:36.743817', '2026-03-27 01:38:56.393218', 2, 2, 'fixed', NULL, 300.00),
	('4f23d105-f0c2-461a-9193-7075d3517eae', 'ad692b74-66e1-4af6-a1b4-e6ed71b22209', '4-Week Full Immersion', 28, 20, 5800.00, NULL, 5394000, 870000, 212000.00, NULL, 7890.00, NULL, '["The ultimate 28-day full English immersion experience in Bangkok — live, breathe, and think in English from morning to night.", "✓ Modern student residence accommodation with air-conditioning and daily breakfast", "✓ 30 English lessons per week — morning intensive sessions and afternoon practice labs", "✓ Suvarnabhumi Airport transfer on program arrival day", "✓ Evening conversation clubs with native speakers five nights per week", "✓ Bangkok cultural full-day tour: Grand Palace, Wat Pho, Chatuchak Market", "✓ Day trip to Ayutthaya ancient kingdom — UNESCO World Heritage Site", "✓ Fluency assessment at start, midpoint, and end — progress tracking included", "✗ International flights and Thailand tourist visa fees not included", "✗ Travel insurance not provided — must be purchased before departure", "✗ Meals outside included breakfast plan at own expense", "✗ Optional Pattaya or Koh Chang beach excursions at additional cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:39:08.128393', 2, 1, NULL, NULL, NULL),
	('272adcf2-613b-4516-a59f-41acebabc29a', 'fddf8d72-2789-454a-ba54-f4046affecf0', '4-Week Standard', 28, 15, 5200.00, 3450.00, 4620000, NULL, NULL, NULL, NULL, NULL, '["A comprehensive 4-week English program in Sydney — standard pace, outstanding results, and unforgettable Australian experiences.", "✓ Host family accommodation in Sydney''s leafy suburbs, breakfast and dinner included", "✓ 25 English lessons per week — general English with conversation focus", "✓ Sydney Airport arrival transfer on program start date", "✓ Three supervised day trips: Blue Mountains, Hunter Valley, and Royal National Park", "✓ Sydney Harbour cruise with commentary — iconic introduction to the city", "✓ Comprehensive travel insurance coverage included for the full 4-week period", "✓ Certificate of completion with teacher''s written assessment and grade", "✗ International airfare from home country not included", "✗ Australian ETA or student visa fees to be paid by participant", "✗ Personal spending money for shopping, eating out, and entertainment", "✗ Optional surf lessons at Bondi Beach or diving experience at Manly"]', 'active', '2026-03-18 01:11:40.328478', '2026-03-27 01:39:16.111845', 1, 1, NULL, NULL, NULL),
	('64b477b9-0105-4227-bf14-824105779de1', 'f904fe12-b84a-4bb8-a219-722e021dafbc', '4-Week Standard', 28, 15, 5200.00, 3450.00, 4620000, NULL, NULL, NULL, NULL, NULL, '["Spend four rewarding weeks mastering English in Vancouver — the perfect blend of classroom learning and breathtaking Canadian nature.", "✓ Host family accommodation in Vancouver with breakfast and dinner on weekdays", "✓ 25 English lessons weekly with a focus on speaking fluency and writing skills", "✓ YVR Airport pickup included on confirmed program arrival date", "✓ Three supervised excursions: Grouse Mountain, Stanley Park bike tour, Granville Island", "✓ Whistler ski village day trip — sightseeing included, ski rental optional", "✓ Comprehensive travel insurance covering medical emergencies included", "✓ Program completion certificate with individual teacher assessment notes", "✗ International airfare not included in package price", "✗ Canadian ETA or study permit fees are participant''s responsibility", "✗ Ski lift tickets and equipment rental at Whistler not included", "✗ Weekend meals at host family on Saturdays and Sundays at own arrangement"]', 'active', '2026-03-21 15:51:37.274692', '2026-03-27 01:39:19.903334', 1, 2, 'percentage', 10.00, NULL),
	('63386a03-9864-4109-88e4-60afe6a6657e', 'f904fe12-b84a-4bb8-a219-722e021dafbc', '4-Week Standard', 28, 15, 5200.00, 3450.00, 4620000, NULL, NULL, NULL, NULL, NULL, '["Four weeks of high-quality standard English study in Vancouver — outstanding teaching, genuine Canadian hospitality, and natural beauty.", "✓ Host family accommodation with home-cooked breakfast and dinner daily", "✓ 25 English lessons per week delivered by TESOL-certified Canadian educators", "✓ Airport transfer from YVR International on first day included", "✓ Three guided day trips: Capilano Suspension Bridge, Richmond Night Market, Squamish", "✓ Intercultural social events — international student dinners and game nights", "✓ Full travel insurance coverage included for the 28-day program duration", "✓ Certificate with comprehensive feedback and graded language portfolio", "✗ Return international airfare from home country not covered", "✗ Canadian student permit or eTA must be applied for independently", "✗ Personal spending on souvenirs, clothes and extra food at own expense", "✗ Optional Sea-to-Sky helicopter tour available at premium supplement"]', 'active', '2026-03-20 02:12:06.10464', '2026-03-27 01:39:23.783585', 2, 1, 'percentage', 10.00, NULL),
	('b3438c1e-0afe-4a2c-9d69-4897648b0e3e', '7d95ca36-9aae-4472-9b51-728da28999e9', '4-Week Standard', 28, 15, 5200.00, 3450.00, 4620000, NULL, NULL, NULL, NULL, NULL, '["Four weeks in Melbourne — the world''s most liveable city — delivering standout English fluency gains in a vibrant cultural setting.", "✓ Host family accommodation in Melbourne''s inner suburbs with meals daily", "✓ 25 English lessons per week blending general English with Melbourne cultural themes", "✓ Melbourne Airport transfer on arrival day from Tullamarine", "✓ Three supervised day trips: Phillip Island penguins, Mornington Peninsula, and Ballarat", "✓ Melbourne laneway and street art guided walking tour with local artist", "✓ Full travel insurance included for the entire 4-week program period", "✓ Certificate of completion and individual teacher evaluation report", "✗ International airfare and Australian ETA visa fees not included", "✗ Travel insurance is included — no additional purchase required", "✗ Personal spending, clothing, and entertainment costs not covered", "✗ Optional Great Ocean Road tour or Yarra Valley wine tour at extra cost"]', 'active', '2026-03-19 13:22:36.727319', '2026-03-27 01:39:27.671303', 2, 2, NULL, NULL, NULL),
	('cb0f26d9-dd65-41aa-bf0f-58b40a046089', 'fddf8d72-2789-454a-ba54-f4046affecf0', 'Copy of 4-Week Standard', 28, NULL, 5200.00, 3450.00, 4620000, NULL, NULL, NULL, NULL, NULL, '["A 4-week standard English program in Sydney — combining solid classroom learning with iconic Australian adventures and sunny beach life.", "✓ Host family accommodation in Greater Sydney with breakfast and dinner included", "✓ 25 English lessons weekly covering general English, idioms, and conversation skills", "✓ Sydney Kingsford Smith Airport transfer provided on day one", "✓ Three guided excursions: Blue Mountains, Bondi to Coogee coastal walk, Manly Ferry", "✓ Taronga Zoo family visit included as a program cultural activity", "✓ Comprehensive travel insurance coverage for the full program period", "✓ Certificate of completion and written assessment from class teacher", "✗ International airfare not included in package pricing", "✗ Australian ETA or student visa to be arranged by participant", "✗ Personal spending, meals out, and souvenirs at own expense", "✗ Optional snorkelling at Manly, surf lessons at Bondi at extra charge"]', 'active', '2026-03-21 14:15:58.31422', '2026-03-27 01:39:35.383879', 2, 1, NULL, NULL, NULL),
	('7a23ce46-e23e-4c08-a3a5-ab27a4363903', 'fddf8d72-2789-454a-ba54-f4046affecf0', '2 Week Basic', 14, 20, 2850.00, 1890.00, 2530000, NULL, NULL, NULL, NULL, NULL, '["A 14-day English foundation program in iconic Sydney — ideal for families wanting structured study with Sydney Harbour views.", "✓ Host family accommodation in Sydney''s eastern or northern suburbs, meals included", "✓ 20 General English lessons per week with qualified native-speaking teachers", "✓ Arrival transfer from Sydney Kingsford Smith Airport provided", "✓ Sydney Harbour Bridge and Opera House orientation walking tour", "✓ One supervised family-friendly weekend excursion — Bondi Beach or Blue Mountains", "✓ Edubee student support app access for scheduling and messaging", "✓ End-of-program certificate with teacher assessment notes", "✗ International airfare to and from Sydney not included", "✗ Travel insurance is not covered and must be purchased separately", "✗ Personal clothing, toiletries and spending money not provided", "✗ Additional weekend tours available at extra cost upon request"]', 'active', '2026-03-18 01:11:40.328478', '2026-03-27 05:46:34.103', 1, 2, NULL, NULL, NULL);
